// settings.ts  (Node.js / TypeScript agent)
import { cleanEnv, str, num, bool, makeValidator } from "envalid";

const oneOf = (...values: string[]) =>
  makeValidator<string>(x => {
    if (values.includes(x)) return x;
    throw new Error(`Expected one of: ${values.join(", ")}`);
  });

export const env = cleanEnv(process.env, {
  OPENAI_API_KEY: str(),
  LLM_MODEL: str({ default: "gpt-4o" }),
  MAX_STEPS: num({ default: 25 }),
  SANDBOX_ENABLED: bool({ default: true }),
  ENVIRONMENT: oneOf("development", "staging", "production")({
    default: "production",
  }),
});

// Usage: env.LLM_MODEL, env.MAX_STEPS — fully typed, validated at startup
